#!/usr/bin/env python3
"""Compile Lean outputs generated by ``using_veribench_with_harbor.py``."""

from __future__ import annotations

import argparse
import json
import pathlib
import re
import subprocess
import time
from dataclasses import asdict, dataclass


HERE = pathlib.Path(__file__).resolve().parent
DEFAULT_INPUT = HERE / "results" / "qwen3_8b_smoke_20task.jsonl"
DEFAULT_LEAN_PROJECT = (
    HERE.parents[2] / "veribench-dt" / "veribench_dataset_dt" / "gold_examples" / "lean_src"
)
DEFAULT_OUT_DIR = HERE / "compiled_outputs" / "qwen3_8b_smoke_20task"
DEFAULT_SUMMARY = HERE / "results" / "qwen3_8b_smoke_20task_compile_summary.json"


@dataclass
class CompileRecord:
    task_name: str
    lean_file: str
    passed: bool
    elapsed_sec: float
    returncode: int
    stderr_tail: str
    stdout_tail: str


def strip_markdown_fence(text: str) -> str:
    match = re.search(r"```(?:lean|lean4)?\s*(.*?)```", text, flags=re.DOTALL | re.IGNORECASE)
    if match:
        return match.group(1).strip() + "\n"
    text = re.sub(r"^\s*```(?:lean|lean4)?\s*", "", text, flags=re.IGNORECASE)
    text = re.sub(r"\s*```\s*$", "", text)
    return text.strip() + "\n"


def safe_file_stem(task_name: str) -> str:
    return re.sub(r"[^A-Za-z0-9_]+", "__", task_name).strip("_") or "task"


def tail(text: str, max_chars: int = 4000) -> str:
    text = text.strip()
    return text[-max_chars:] if len(text) > max_chars else text


def compile_file(lean_project: pathlib.Path, lean_file: pathlib.Path, timeout: int) -> CompileRecord:
    start = time.monotonic()
    result = subprocess.run(
        ["lake", "env", "lean", str(lean_file)],
        cwd=lean_project,
        text=True,
        capture_output=True,
        timeout=timeout,
        check=False,
    )
    elapsed = time.monotonic() - start
    return CompileRecord(
        task_name=lean_file.stem,
        lean_file=str(lean_file),
        passed=result.returncode == 0,
        elapsed_sec=round(elapsed, 3),
        returncode=result.returncode,
        stderr_tail=tail(result.stderr),
        stdout_tail=tail(result.stdout),
    )


def main() -> None:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("--input", type=pathlib.Path, default=DEFAULT_INPUT)
    parser.add_argument("--lean-project", type=pathlib.Path, default=DEFAULT_LEAN_PROJECT)
    parser.add_argument("--out-dir", type=pathlib.Path, default=DEFAULT_OUT_DIR)
    parser.add_argument("--summary", type=pathlib.Path, default=DEFAULT_SUMMARY)
    parser.add_argument("--timeout", type=int, default=120)
    args = parser.parse_args()

    args.out_dir.mkdir(parents=True, exist_ok=True)
    args.summary.parent.mkdir(parents=True, exist_ok=True)

    rows = [json.loads(line) for line in args.input.read_text(encoding="utf-8").splitlines() if line.strip()]
    records: list[CompileRecord] = []
    for idx, row in enumerate(rows, start=1):
        stem = safe_file_stem(row["task_name"])
        lean_file = args.out_dir / f"{idx:03d}_{stem}.lean"
        lean_file.write_text(strip_markdown_fence(row["output_text"]), encoding="utf-8")
        print(f"[{idx}/{len(rows)}] compiling {row['task_name']}", flush=True)
        record = compile_file(args.lean_project, lean_file.resolve(), args.timeout)
        record.task_name = row["task_name"]
        records.append(record)

    passed = sum(record.passed for record in records)
    summary = {
        "input": str(args.input),
        "lean_project": str(args.lean_project),
        "out_dir": str(args.out_dir),
        "num_tasks": len(records),
        "passed": passed,
        "failed": len(records) - passed,
        "compile_pass_rate": passed / len(records) if records else 0.0,
        "records": [asdict(record) for record in records],
    }
    args.summary.write_text(json.dumps(summary, indent=2), encoding="utf-8")
    print(json.dumps({k: v for k, v in summary.items() if k != "records"}, indent=2))


if __name__ == "__main__":
    main()
